constexpr int kFullThreadsPerBlock = 256;
constexpr int kHalfThreadsPerBlock = 128;
constexpr int kReduceThreads = 256;
constexpr size_t kStaticChunkSize = 4096;

template <typename T, int BLOCK_THREADS>
__global__ void reduce_sum_kernel(const T* __restrict__ in,
                                  T* __restrict__ out,
                                  size_t n) {
  size_t idx = static_cast<size_t>(blockIdx.x) * (BLOCK_THREADS * 2) +
               static_cast<size_t>(threadIdx.x);

  T sum = 0;
  if (idx < n) sum += in[idx];
  if (idx + BLOCK_THREADS < n) sum += in[idx + BLOCK_THREADS];

  __shared__ T sdata[BLOCK_THREADS];
  sdata[threadIdx.x] = sum;
  __syncthreads();

  for (int stride = BLOCK_THREADS / 2; stride > 0; stride >>= 1) {
    if (threadIdx.x < stride) {
      sdata[threadIdx.x] += sdata[threadIdx.x + stride];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    out[blockIdx.x] = sdata[0];
  }
}

template <typename T>
__global__ void write_back_kernel(T* dst, const T* src) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    dst[0] = src[0];
  }
}

