template <typename Element, size_t compute_iterations, int BLOCK_THREADS>
void bench_launch(size_t len,
                  Element* src,
                  Element* partial1,
                  Element* partial2) {
  const size_t blocks = (len + kStaticChunkSize - 1) / kStaticChunkSize;

  bench_kernel<Element, compute_iterations, BLOCK_THREADS>
      <<<static_cast<unsigned int>(blocks), BLOCK_THREADS>>>(src, len, partial1);

  size_t current = blocks;
  Element* in = partial1;
  Element* out = partial2;

  while (current > 1) {
    const size_t reduce_blocks =
        (current + (kReduceThreads * 2 - 1)) / (kReduceThreads * 2);
    reduce_sum_kernel<Element, kReduceThreads>
        <<<static_cast<unsigned int>(reduce_blocks), kReduceThreads>>>(in, out,
                                                                       current);
    current = reduce_blocks;
    Element* tmp = in;
    in = out;
    out = tmp;
  }

  write_back_kernel<Element><<<1, 1>>>(src, in);
}

template <typename Element, size_t compute_iterations>
size_t bench(size_t len,
             const Element seed1,
             const Element seed2,
             Element* src,
             void* partial1_raw,
             void* partial2_raw,
             int threads_per_block) {
  (void)seed1;
  (void)seed2;

  Element* partial1 = reinterpret_cast<Element*>(partial1_raw);
  Element* partial2 = reinterpret_cast<Element*>(partial2_raw);

  if (threads_per_block <= kHalfThreadsPerBlock) {
    bench_launch<Element, compute_iterations, kHalfThreadsPerBlock>(
        len, src, partial1, partial2);
  } else {
    bench_launch<Element, compute_iterations, kFullThreadsPerBlock>(
        len, src, partial1, partial2);
  }

  CUDA_SAFE_CALL(cudaGetLastError());
  return len;
}

struct GPUContext {
  void* d_buffer{nullptr};
  void* d_partial1{nullptr};
  void* d_partial2{nullptr};
  size_t memory_space_bytes{0};
};

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start, 0));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop, 0));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float elapsed_ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed_ms, start, stop));
  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));

  return static_cast<double>(elapsed_ms);
}

template <typename Op>
double benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  (void)op(kFullThreadsPerBlock);

  std::vector<double> measurements;
  measurements.reserve((total_runs - 1) + (total_half_thread_runs - 1));

  for (int i = 1; i < total_runs; i++) {
    measurements.push_back(op(kFullThreadsPerBlock));
  }

  if (kFullThreadsPerBlock > 1) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      measurements.push_back(op(kHalfThreadsPerBlock));
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

void runbench_warmup(GPUContext& ctx) {
  const size_t num_elements = ctx.memory_space_bytes / sizeof(double);
  double* ptr = reinterpret_cast<double*>(ctx.d_buffer);
  bench<double, 16>(num_elements, 1.0, -1.0, ptr, ctx.d_partial1,
                    ctx.d_partial2, kFullThreadsPerBlock);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());
}

template <unsigned int compute_iterations>
void runbench(GPUContext& ctx) {
  ComputeSpace cs{ctx.memory_space_bytes, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(ctx.d_buffer);
  auto kernel_time_mad_sp = benchmark_cuda([&](int threads_per_block) {
    return measure_operation([&] {
      bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                       c_as_float, ctx.d_partial1,
                                       ctx.d_partial2, threads_per_block);
    });
  });

  double* c_as_double = reinterpret_cast<double*>(ctx.d_buffer);
  auto kernel_time_mad_dp = benchmark_cuda([&](int threads_per_block) {
    return measure_operation([&] {
      bench<double, compute_iterations>(cs.element_count<double>(), 1.0, -1.0,
                                        c_as_double, ctx.d_partial1,
                                        ctx.d_partial2, threads_per_block);
    });
  });

  int* c_as_int = reinterpret_cast<int*>(ctx.d_buffer);
  auto kernel_time_mad_int = benchmark_cuda([&](int threads_per_block) {
    return measure_operation([&] {
      bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int,
                                     ctx.d_partial1, ctx.d_partial2,
                                     threads_per_block);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000.0 / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000.0 / (1000.0 * 1000.0 * 1000.0)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000.0 / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000.0 / (1000.0 * 1000.0 * 1000.0)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000.0 / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000.0 / (1000.0 * 1000.0 * 1000.0)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(GPUContext& ctx) {
  runbench<compute_iterations>(ctx);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(GPUContext& ctx) {
  runbench_range<j1>(ctx);
  runbench_range<j2, Args...>(ctx);
}

