extern "C" void mixbenchGPU(double* c, long size) {
  const size_t memory_space_bytes =
      static_cast<size_t>(size) * sizeof(double);

  GPUContext ctx;
  ctx.memory_space_bytes = memory_space_bytes;

  CUDA_SAFE_CALL(cudaMalloc(&ctx.d_buffer, memory_space_bytes));

  const size_t max_elements_as_int = memory_space_bytes / sizeof(int);
  const size_t max_partial_count =
      (max_elements_as_int + kStaticChunkSize - 1) / kStaticChunkSize;
  const size_t partial_bytes = max_partial_count * sizeof(double);

  CUDA_SAFE_CALL(cudaMalloc(&ctx.d_partial1, partial_bytes));
  CUDA_SAFE_CALL(cudaMalloc(&ctx.d_partial2, partial_bytes));
  CUDA_SAFE_CALL(cudaMemset(ctx.d_buffer, 0, memory_space_bytes));
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(ctx);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(ctx);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  if (c != nullptr) {
    CUDA_SAFE_CALL(cudaMemcpy(c, ctx.d_buffer, sizeof(double),
                              cudaMemcpyDeviceToHost));
  }

  CUDA_SAFE_CALL(cudaFree(ctx.d_partial2));
  CUDA_SAFE_CALL(cudaFree(ctx.d_partial1));
  CUDA_SAFE_CALL(cudaFree(ctx.d_buffer));
}
